, UPDATEDATE = #{sysdate} /* 수정일시 */ , UPDATEURKEY = #{surkey} /* 수정사용자 */ WHERE CTKEY = #{ctkey} /* 센터코드 */ AND OWKEY = #{owkey} /* 화주코드 */ AND ICKEY = #{ickey} /* 상품 코드 */ AND ICUNITTYPECD = #{icunittype} /* 상품 단위 유형 */

